// Node.js'in yerleşik dosya sistemi modülünü içeri alıyoruz
const fs = require('fs');
const path = require('path');

// 1. En baştaki 'Senaryo Ayarları' nodundan ana bilgileri çekiyoruz
const scenarioName = $('Senaryo Ayarları').first().json.scenarioName;
const targetUrl = $('Senaryo Ayarları').first().json.targetUrl;

const steps = [];
const stepNodeNames = ['Adım 1 - Tıkla', 'Adım 2 - Doğrula'];

for (const nodeName of stepNodeNames) {
    try {
        const nodeData = $(nodeName).first().json;
        if (nodeData && nodeData.type) {
            let stepObj = {
                type: nodeData.type,
                instruction: nodeData.instruction
            };
            if (nodeData.field) {
                stepObj.field = nodeData.field;
            }
            steps.push(stepObj);
        }
    } catch (error) {
        console.warn(`Düğüm okunurken hata oluştu (${nodeName}):`, error.message);
    }
}

// 2. Oluşturulacak temiz JSON metni
const finalJsonData = {
  targetUrl: targetUrl,
  steps: steps
};

// 3. Hedef dosya yolunu ve adını belirliyoruz
const targetFolder = 'C:/Users/feyza/Desktop/test-tool/scenarios';
const fullPath = path.join(targetFolder, `${scenarioName}.json`);

try {
    // Klasörün varlığını kontrol et, yoksa oluştur
    if (!fs.existsSync(targetFolder)){
        fs.mkdirSync(targetFolder, { recursive: true });
    }

    // Dosyayı n8n katmanlarını aradan çıkararak direkt Node.js ile diske çakıyoruz kanka
    fs.writeFileSync(fullPath, JSON.stringify(finalJsonData, null, 2), 'utf-8');

    return [{
      json: {
        status: "Başarılı",
        message: `Senaryo başarıyla oluşturuldu: ${scenarioName}.json`,
        savedPath: fullPath
      }
    }];

} catch (writeError) {
    // Bir hata olursa n8n ekranında görebilelim
    return [{
      json: {
        status: "Hata",
        message: writeError.message
      }
    }];
}
